@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@attribute [Microsoft.AspNetCore.Components.Endpoints.ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    Your privacy is important to us. This page describes how we collect, use,
    and protect your personal information.
</p>

@if (HasConsented)
{
    <div class="alert alert-success" role="alert">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning" role="alert">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        if (HttpContext is not null &&
            HttpContext.Request.Cookies.TryGetValue("consent", out var value))
        {
            HasConsented = string.Equals(value, "true", StringComparison.OrdinalIgnoreCase);
        }
    }
}

